import {
  createBrowserRouter,
  redirect,
  RouterProvider,
} from "react-router-dom";

import Layout from "./components/Layout/Layout";
import ServerNav from "./components/ServerNav/ServerNav";
import Sidebar from "./components/Sidebar/Sidebar";
import Chat from "./pages/DM/Chat";
import Login from "./pages/Auth/Login";
import Register from "./pages/Auth/Register";
import { useEffect, useState } from "react";

function App() {
  const [isAuth, setIsAuth] = useState(false);
  const [token, setToken] = useState(null);

  useEffect(() => {
    const token = localStorage.getItem("token");
    const expiryDate = localStorage.getItem("expirationTime");

    if (!token) {
      return;
    }

    if (expiryDate) {
    }

    setToken(token);
    setIsAuth(true);
  }, []);

  console.log(token);
  console.log(isAuth);

  const router = createBrowserRouter([
    {
      path: "/register",
      element: (
        <Layout>
          <Register />
        </Layout>
      ),
    },
    {
      path: "/login",
      loader: () => {
        if (isAuth) return redirect("/");
        return null;
      },
      element: (
        <Layout>
          <Login />
        </Layout>
      ),
    },
    {
      path: "/",
      loader: () => {
        if (!isAuth) return redirect("/login");
        return null;
      },
      element: <Chat token={token}></Chat>,
    },
  ]);

  return (
    <Layout nav={isAuth && <ServerNav />} sidebar={isAuth && <Sidebar />}>
      <RouterProvider router={router}></RouterProvider>;
    </Layout>
  );
}

export default App;
